const body=$input.first().json;
let phone='',message='',pushName='';
if(body.data?.key){
  const d=body.data;
  if(d.key?.fromMe||d.key?.remoteJid?.endsWith('@g.us'))return[];
  phone=(d.key?.remoteJid||'').replace('@s.whatsapp.net','').replace(/\D/g,'');
  message=d.message?.conversation||d.message?.extendedTextMessage?.text||d.message?.buttonsResponseMessage?.selectedButtonId||'';
  pushName=d.pushName||'';
}else if(body.event==='messages.upsert'&&body.data){
  const d=body.data;
  if(d.key?.fromMe||d.key?.remoteJid?.endsWith('@g.us'))return[];
  phone=(d.key?.remoteJid||'').replace('@s.whatsapp.net','').replace(/\D/g,'');
  message=d.message?.conversation||d.message?.extendedTextMessage?.text||'';
  pushName=d.pushName||'';
}else if(body.phone!==undefined){
  if(body.fromMe||body.isGroup)return[];
  phone=(body.phone||'').replace(/\D/g,'');
  message=body.text?.message||body.text||'';
  pushName=body.senderName||'';
}else return[];
if(!phone||!message.trim())return[];
if(!phone.startsWith('55'))phone='55'+phone;
return[{json:{phone,message:message.trim(),ml:message.trim().toLowerCase().replace(/[\u{1F300}-\u{1F9FF}]/gu,'').trim(),pushName,ts:new Date().toISOString()}}];

