if(!sd.sessions[key])sd.sessions[key]={state:'novo',cat:null,catLabel:null,catIcon:null,priority:'Media',espaco:null,espacoLabel:null,dataReserva:null,_ts:now};
sd.sessions[key]._ts=now;
return[{json:{...d,session:{...sd.sessions[key]},sessionKey:key}}];

