const d=$input.first().json;
const csvUrl=$vars.ENCOMENDAS_CSV_URL||'';
const ev=$vars.EVOLUTION_API_URL||'http://localhost:8080';
const inst=$vars.EVOLUTION_API_INSTANCE||'condo';
const key=$vars.EVOLUTION_API_KEY||'';
let txt='';
if(!csvUrl){
  txt='📦 Sistema de encomendas em configuração.\n\nProcure a portaria pessoalmente. 🙂';
  return[{json:{phone:d.phone,txt,ev,inst,key}}];
}
try{
  const sep=csvUrl.includes('?')?'&':'?';
  const r=await fetch(csvUrl+sep+'_='+Date.now());
  const raw=await r.text();
  const rows=raw.trim().split('\n').map(l=>{
    const cols=[];let cur='',inQ=false;
    for(const ch of l){if(ch==='"')inQ=!inQ;else if(ch===','&&!inQ){cols.push(cur);cur='';}else cur+=ch;}
    cols.push(cur);return cols;
  });
  if(rows.length<2){txt='📭 Nenhuma encomenda no momento.\n\nAssim que chegar algo, avisamos! 😊';}
  else{
    const hdr=rows[0].map(h=>h.trim());
    const get=(row,col)=>(row[hdr.indexOf(col)]||'').trim();
    const phone=d.phone.replace(/\D/g,'');
    const enc=rows.slice(1).filter(row=>get(row,'phone').replace(/\D/g,'')==phone&&get(row,'status')!=='Retirada');
    if(!enc.length){txt='📭 Nenhuma encomenda pendente no momento.\n\nAssim que chegar algo, avisamos! 😊';}
    else{
      const lista=enc.map((row,i)=>`${i+1}. 📦 ${get(row,'remetente')||'Remetente não informado'} — chegou ${get(row,'data_chegada')}`).join('\n');
      txt=`📦 *Você tem ${enc.length} encomenda(s) na portaria:*\n\n${lista}\n\nRetire em horário comercial.\n\nDigite *menu* para voltar.`;
    }
  }
}catch(e){
  txt='📦 Não foi possível verificar encomendas agora. Tente novamente em breve.';
}
return[{json:{phone:d.phone,txt,ev,inst,key}}];

