const d=$input.first().json;
const apiKey=$vars.ANTHROPIC_API_KEY||'';
const sd=$getWorkflowStaticData('global');
const ev=$vars.EVOLUTION_API_URL||'http://localhost:8080';
const inst=$vars.EVOLUTION_API_INSTANCE||'condo';
const key=$vars.EVOLUTION_API_KEY||'';
const intentMap={
  solicitacao:{label:'Solicitação',state:'aguardando_categoria',cat:null},
  protocolo:{label:'Protocolo',state:'aguardando_protocolo',cat:null},
  encomenda:{label:'Encomenda',state:'__encomenda__',cat:null},
  reserva:{label:'Reserva',state:'aguardando_espaco',cat:null},
  sindico:{label:'Síndico',state:'aguardando_detalhes',cat:'outros',catLabel:'Contato Síndico',catIcon:'👤'}
};
if(!apiKey){
  const sess=sd.sessions[d.sessionKey]||{};
  sess.state='aguardando_menu_principal';
  sd.sessions[d.sessionKey]=sess;
  const nome=$vars.CONDO_NAME||'Condomínio';
  const txt=`🏢 *${nome}*\n\nNão entendi. Use as opções:\n\n1️⃣ 🔧  Abrir solicitação\n2️⃣ 🔍  Protocolo\n3️⃣ 📦  Encomendas\n4️⃣ 🗓️  Reservar espaço\n0️⃣ 👤  Síndico`;
  return[{json:{phone:d.phone,pushName:d.pushName,sessionKey:d.sessionKey,__action:'menu_fallback',txt,ev,inst,key}}];
}
try{
  const r=await fetch('https://api.anthropic.com/v1/messages',{
    method:'POST',
    headers:{'x-api-key':apiKey,'anthropic-version':'2023-06-01','content-type':'application/json'},
    body:JSON.stringify({
      model:'claude-haiku-4-5-20251001',
      max_tokens:60,
      system:'Classifique a mensagem do morador de condomínio em UMA das intenções: solicitacao, protocolo, encomenda, reserva, sindico. Responda APENAS com o JSON: {"intent":"solicitacao"}',
      messages:[{role:'user',content:`Mensagem: "${d.message}"`}]
    })
  });
  const res=await r.json();
  const text=res.content?.[0]?.text||'{}';
  const m=text.match(/\{[^}]+\}/);
  const parsed=m?JSON.parse(m[0]):{};
  const intent=parsed.intent in intentMap?parsed.intent:'solicitacao';
  const info=intentMap[intent];
  const sess=sd.sessions[d.sessionKey]||{};
  if(info.state==='__encomenda__'){
    return[{json:{...d,__action:'encomenda',ev,inst,key}}];
  }
  sess.state=info.state;
  if(info.cat){sess.cat=info.cat;sess.catLabel=info.catLabel;sess.catIcon=info.catIcon;sess.priority='Media';}
  sd.sessions[d.sessionKey]=sess;
  return[{json:{...d,__intent:intent,__action:info.state,ev,inst,key}}];
}catch(e){
  return[{json:{...d,__action:'menu_fallback',ev,inst,key}}];
}

const d=$input.first().json;
const sd=$getWorkflowStaticData('global');
