}
const csvUrl=$vars.SHEETS_CSV_URL||'';
const ev=$vars.EVOLUTION_API_URL||'http://localhost:8080';
const inst=$vars.EVOLUTION_API_INSTANCE||'condo';
const key=$vars.EVOLUTION_API_KEY||'';
const proto=d.message.trim().toUpperCase();
const sess=sd.sessions[d.sessionKey]||{};
sess.state='aguardando_menu_principal';
sd.sessions[d.sessionKey]=sess;
if(!csvUrl){
  return[{json:{phone:d.phone,__found:false,__cancel:false,txt:'🔍 Sistema de consulta em configuração. Tente novamente em breve.',ev,inst,key}}];
}
try{
  const sep=csvUrl.includes('?')?'&':'?';
  const r=await fetch(csvUrl+sep+'_='+Date.now());
  const raw=await r.text();
  const rows=raw.trim().split('\n').map(l=>{
    const cols=[];let cur='',inQ=false;
    for(const ch of l){if(ch==='"')inQ=!inQ;else if(ch===','&&!inQ){cols.push(cur);cur='';}else cur+=ch;}
    cols.push(cur);return cols;
  });
  const hdr=rows[0].map(h=>h.trim());
  const get=(row,col)=>(row[hdr.indexOf(col)]||'').trim();
  const found=rows.slice(1).find(row=>get(row,'protocolo').toUpperCase()===proto);
  if(!found){
    const txt=`❌ Protocolo *${proto}* não encontrado.\n\nVerifique o número e tente novamente, ou digite *menu*.`;
    return[{json:{phone:d.phone,__found:false,__cancel:false,txt,ev,inst,key}}];
  }
  const statusIco={Aberta:'🔵',"Em andamento":'🔄',Resolvida:'✅',Cancelada:'⛔'};
  const status=get(found,'status');
  const txt=`✅ *Protocolo ${proto}*\n\n${get(found,'icone')||'📋'} *${get(found,'categoria')}*\n👤 ${get(found,'morador')}\n📅 ${get(found,'data')} às ${get(found,'hora')}\n\nStatus: ${statusIco[status]||'📋'} *${status}*\n\n_${status==='Resolvida'?'Solicitação concluída!':'Nossa equipe está cuidando disso.'}_\n\nDigite *menu* para voltar.`;
  return[{json:{phone:d.phone,__found:true,__cancel:false,txt,ev,inst,key}}];
}catch(e){
  return[{json:{phone:d.phone,__found:false,__cancel:false,txt:'❌ Erro ao consultar. Tente novamente em breve.',ev,inst,key}}];
}

