const d=$input.first().json;
const sd=$getWorkflowStaticData('global');
const sess=sd.sessions[d.sessionKey]||{};
const cancelWords=['cancelar','cancel','menu','voltar','0'];
const ev=$vars.EVOLUTION_API_URL||'http://localhost:8080';
