if(cancelWords.includes(d.ml)){
  sess.state='aguardando_menu_principal';
  sd.sessions[d.sessionKey]=sess;
  return[{json:{...d,__available:false,__cancel:true,ev,inst,key}}];
}
const raw=d.message.trim();
const dateMatch=raw.match(/(\d{1,2})[\/-](\d{1,2})(?:[\/-](\d{2,4}))?/);
if(!dateMatch){
  const txt=`⚠️ Não entendi a data. Informe no formato:\n_(Ex: 25/05 ou 25/05/2026)_`;
  return[{json:{phone:d.phone,__available:false,__cancel:false,__invalid:true,txt,ev,inst,key}}];
}
const day=dateMatch[1].padStart(2,'0');
const month=dateMatch[2].padStart(2,'0');
const year=dateMatch[3]?(dateMatch[3].length===2?'20'+dateMatch[3]:dateMatch[3]):new Date().getFullYear();
const dataFormatada=`${day}/${month}/${year}`;
sess.dataReserva=dataFormatada;
sd.sessions[d.sessionKey]=sess;
const csvUrl=$vars.RESERVAS_CSV_URL||'';
if(!csvUrl){
  sess.state='aguardando_confirm_reserva';
  sd.sessions[d.sessionKey]=sess;
  const icon=sess.espacoIcon||'🗓️';
  const label=sess.espacoLabel||sess.espaco;
  const txt=`✅ *${dataFormatada}* está disponível!\n\n${icon} *${label}*\n👤 ${d.pushName||d.phone}\n\nConfirmar reserva?\n\n1️⃣  Sim, confirmar\n2️⃣  Escolher outra data\n0️⃣  Cancelar`;
  return[{json:{phone:d.phone,pushName:d.pushName,sessionKey:d.sessionKey,__available:true,__cancel:false,dataFormatada,txt,ev,inst,key}}];
}
try{
  const sep=csvUrl.includes('?')?'&':'?';
  const r=await fetch(csvUrl+sep+'_='+Date.now());
  const rawCsv=await r.text();
  const rows=rawCsv.trim().split('\n').map(l=>{
    const cols=[];let cur='',inQ=false;
    for(const ch of l){if(ch==='"')inQ=!inQ;else if(ch===','&&!inQ){cols.push(cur);cur='';}else cur+=ch;}
    cols.push(cur);return cols;
  });
  const hdr=rows[0].map(h=>h.trim());
  const get=(row,col)=>(row[hdr.indexOf(col)]||'').trim();
  const ocupado=rows.slice(1).some(row=>get(row,'espaco')===sess.espaco&&get(row,'data')===dataFormatada&&get(row,'status')!=='Cancelada');
  const icon=sess.espacoIcon||'🗓️';
  const label=sess.espacoLabel||sess.espaco;
  if(ocupado){
    const txt=`❌ *${dataFormatada}* já está reservado para o ${label}.\n\nEscolha outra data:\n_(Ex: 27/05)_\n\nOu digite *cancelar*.`;
    return[{json:{phone:d.phone,pushName:d.pushName,sessionKey:d.sessionKey,__available:false,__cancel:false,dataFormatada,txt,ev,inst,key}}];
  }
  sess.state='aguardando_confirm_reserva';
  sd.sessions[d.sessionKey]=sess;
  const txt=`✅ *${dataFormatada}* está disponível!\n\n${icon} *${label}*\n👤 ${d.pushName||d.phone}\n\nConfirmar reserva?\n\n1️⃣  Sim, confirmar\n2️⃣  Escolher outra data\n0️⃣  Cancelar`;
  return[{json:{phone:d.phone,pushName:d.pushName,sessionKey:d.sessionKey,__available:true,__cancel:false,dataFormatada,txt,ev,inst,key}}];
}catch(e){
  sess.state='aguardando_confirm_reserva';
  sd.sessions[d.sessionKey]=sess;
  const icon=sess.espacoIcon||'🗓️';const label=sess.espacoLabel||sess.espaco;
  const txt=`✅ *${dataFormatada}* parece disponível!\n\n${icon} *${label}*\n\nConfirmar reserva?\n\n1️⃣  Sim\n2️⃣  Outra data\n0️⃣  Cancelar`;
  return[{json:{phone:d.phone,pushName:d.pushName,sessionKey:d.sessionKey,__available:true,__cancel:false,dataFormatada,txt,ev,inst,key}}];
}

