const d=$input.first().json;
const apiKey=$vars.ANTHROPIC_API_KEY||'';
const catMap={manutencao:{label:'Manutenção',icon:'🔧',question:'🔧 Entendi! Descreva melhor o problema:\n_(ou *cancelar* para voltar)_',priority:'Media'},financeiro:{label:'Financeiro',icon:'💰',question:'💰 Entendi! Descreva sua questão:\n_(ou *cancelar* para voltar)_',priority:'Alta'},seguranca:{label:'Segurança',icon:'🔐',question:'🔐 Entendi! Descreva o problema de segurança:\n_(ou *cancelar* para voltar)_',priority:'Urgente'},barulho:{label:'Barulho/Perturbação',icon:'🔊',question:'🔊 Entendi! Informe local e horário:\n_(ou *cancelar* para voltar)_',priority:'Alta'},areas:{label:'Áreas Comuns',icon:'🏊',question:'🏊 Entendi! Descreva o problema na área:\n_(ou *cancelar* para voltar)_',priority:'Media'},outros:{label:'Outros',icon:'📋',question:'📋 Entendi! Me dê mais detalhes:\n_(ou *cancelar* para voltar)_',priority:'Media'}};
if(!apiKey){const c=catMap.outros;return[{json:{...d,catKey:'outros',catLabel:c.label,catIcon:c.icon,catQuestion:c.question,priority:c.priority}}];}
try{
  const r=await fetch('https://api.anthropic.com/v1/messages',{method:'POST',headers:{'x-api-key':apiKey,'anthropic-version':'2023-06-01','content-type':'application/json'},body:JSON.stringify({model:'claude-haiku-4-5-20251001',max_tokens:80,system:'Classifique a mensagem do morador. Responda APENAS com JSON: {"cat":"manutencao|financeiro|seguranca|barulho|areas|outros","priority":"Baixa|Media|Alta|Urgente"}',messages:[{role:'user',content:`Classifique: "${d.message}"`}]}));
  const res=await r.json();
  const m=(res.content?.[0]?.text||'{}').match(/\{[^}]+\}/);
  const parsed=m?JSON.parse(m[0]):{};
  const ck=parsed.cat in catMap?parsed.cat:'outros';
  const info=catMap[ck];
